import React, { useEffect, useState } from "react";
import { api } from "../api";

export default function Recipes({ onError }) {
  const [data, setData] = useState({ at_risk_items: [], recipes: [] });

  async function load() {
    try {
      const res = await api.getRecipes();
      setData(res);
    } catch (e) {
      onError(e.message);
    }
  }

  useEffect(() => {
    load();
  }, []);

  return (
    <div className="card">
      <h2>Recipes</h2>

      <h3>At-Risk Items (≤ 48h)</h3>
      {data.at_risk_items?.length ? (
        <ul>
          {data.at_risk_items.map((item, i) => (
            <li key={i}>
              {item.name}{" "}
              {item.days_to_expiry < 0
                ? `— expired ${Math.abs(item.days_to_expiry)} day(s) ago`
                : `— expires in ${item.days_to_expiry} day(s)`}
            </li>
          ))}
        </ul>
      ) : (
        <p className="small">No at-risk items right now.</p>
      )}

      <h3>Recommended Recipes</h3>
      {data.recipes?.length ? (
        data.recipes.map((recipe, i) => (
          <div className="card" key={i}>
            <h3>{recipe.title}</h3>

            <div className="small">
              Score: <b>{recipe.score ?? 0}</b>
            </div>

            <p>
              <b>Ingredients:</b>{" "}
              {Array.isArray(recipe.ingredients)
                ? recipe.ingredients
                    .map((ing) =>
                      typeof ing === "string"
                        ? ing
                        : ing?.name || JSON.stringify(ing)
                    )
                    .join(", ")
                : "N/A"}
            </p>

            {Array.isArray(recipe.steps) && recipe.steps.length > 0 ? (
              <div>
                <b>Steps:</b>
                <ol>
                  {recipe.steps.map((step, idx) => (
                    <li key={idx}>{step}</li>
                  ))}
                </ol>
              </div>
            ) : (
              <p className="small">No steps available.</p>
            )}
          </div>
        ))
      ) : (
        <p className="small">No cookable recipes found (add more items or add more recipes).</p>
      )}
    </div>
  );
}
